var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"여기는 시렌 추격전대…! 단방향 송신기를 통해 본부로 긴급 상황을 전파합니다!","JPN":"こちら、シレン追撃戦隊……！　単方向の送信機を通じて本部に緊急状況をお伝えします！","ENG":"This is the Sirin Tracking Division...! Sending an emergency message to HQ through a one-way transmitter!","TWN":"這裡是賽蓮追擊隊……！透過單向傳輸器向總部發送緊急情況！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"사도의 전력이 예상한 것보다 압도적으로 강합니다…!","JPN":"使徒の戦力が予想よりも圧倒的に強いです……！","ENG":"The Apostle's power is overwhelmingly more powerful than we expected...!","TWN":"使徒的戰力比預想的要強大太多……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리 전대는 궤멸에 가까운 타격을 입었고…! 생존한 대원들은 시간을 벌 수 있도록 산개했습니다!","JPN":"こちらの戦隊は壊滅に近いダメージを受け……！　生き残った隊員たちは時間を稼げるように散開中であります！","ENG":"Our division has suffered a critical blow that was close to annihilation...! The surviving members have been ordered to scatter to buy more time!","TWN":"我們的部隊遭受了毀滅性的打擊……！倖存的隊員們為了爭取時間採取了分散策略！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"승산은 없습니다! 격리된 사도는 예정보다 빨리 풀려날 겁니다!","JPN":"勝ち目はありません！　隔離された使徒は予定より早く解放されるでしょう！","ENG":"There is no hope! The isolated Apostle will be released sooner than expected!","TWN":"勝算幾乎為零！被隔離的使徒將會比預期更早是放出來！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"펜릴이 마왕을 서둘러 처치하지 않으면…!","JPN":"早くフェンリルが魔王を始末しないと……！","ENG":"If the Fenrir doesn't defeat the Demon Lord soon...!","TWN":"如果芬里爾不趕快解決魔王的話……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Errgh...!","TWN":"呃……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"숨을 수 있을 줄 알았어?","JPN":"隠れられるとでも思ったのか？","ENG":"Did you really think you could hide from me?","TWN":"你以為能躲得了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 피를 흘리고 있으면, 냄새로 찾아낼 수 밖에 없잖아. 사냥감.","JPN":"それだけ血を流してたら、匂いで探せるんだ。獲物。","ENG":"I can smell you right away when you're bleeding that much, prey.","TWN":"流了那麼多血，我只靠氣味就找到你了，獵物。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"날… 먼저 쫓아온 건가?","JPN":"私を……先に狙って来たのか？","ENG":"Did you... come after me first?","TWN":"怎麼……是先來追我了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아니? 다른 녀석들은 진작에 처리했는데?","JPN":"いや？　他の奴らはすでに始末した。","ENG":"No. I already took care of the others a long time ago.","TWN":"哈？其他傢伙我早就解決了好嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"네가 마지막이야.","JPN":"あんたが最後だな。","ENG":"You're the last one.","TWN":"你是最後一個。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"안돼… 이렇게 빨리 전멸하면 본대가…!","JPN":"駄目だ……こんなに早く全滅したら本隊が……！","ENG":"No... If we are wiped out this fast, the main forces will–!","TWN":"不……如果這麼快就全軍覆沒的話，主力部隊會……！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아, 그건 걱정 마. 난 처음부터 너희랑 놀아주러 온 거니까.","JPN":"あ、それなら心配するな。アタシは最初からあんたたちと遊ぶために来たんだからな。","ENG":"Oh, don't you worry about that. I came here to play with you from the start.","TWN":"啊，別擔心。我一開始就是來陪你們玩的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"우리 마왕님은 <color=#ffd34c>진짜</color> 싸움을 즐길 때 방해 받는 걸 싫어하시거든.","JPN":"うちの主様は<color=#ffd34c>本物</color>の戦いを楽しむ時に邪魔されるのが嫌いなんだ。","ENG":"Our Demon Lord hates being bothered when she's enjoying a <color=#ffd34c>real</color> fight.","TWN":"我們的魔王大人<color=#ffd34c>真的</color>不喜歡在享受戰鬥時被打擾。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"다른 조무래기가 끼어들면 흥이 깨지니 말이야.","JPN":"他の雑魚が割り込むと興が冷めるからな。","ENG":"And her excitement will be ruined if grunts like you butt in.","TWN":"像你這樣的小嘍囉插手的話，會很掃興的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"사도 없이도… 마왕이 승리를 확신하고 있다고?","JPN":"使徒なしでも……魔王が勝利を確信しているだと？","ENG":"Even without her Apostles... the Demon Lord is certain of her victory?","TWN":"沒有使徒……魔王也敢保證自己的勝利嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하핫, 당연하잖아. 사도에게 의지하는 나약한 것들과 우리 주인님은 다르거든.","JPN":"ははっ、当たり前だろう。主様は使徒に頼る弱いものどもとは違う。","ENG":"Haha! Of course! My mistress is different from those weaklings that rely on their Apostles.","TWN":"哈哈，當然了！我們的主人和依賴使徒的那些弱者可不同！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"자, 넌 무슨 능력으로 날 재밌게 해줄 거지? 어서 보여줘.","JPN":"さあ、あんたはどんな能力でアタシを楽しませてくれるんだ？　早く見せてくれ。","ENG":"Now, with what ability will you entertain me? Let's see it.","TWN":"來，你打算用什麼能力來讓我開心呢？快點展示一下吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"응? 너 설마 능력이 없는 거냐?","JPN":"あ？　あんた、まさか能力がないのか？","ENG":"Hmm? You don't have any ability?","TWN":"什麼啊？你難道沒有能力嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"이거 김 빠지네. 부하 녀석들도 시원찮던데. 뭘 믿고 너희 같은 녀석들에게 날 맡긴 거지?","JPN":"興覚めだな。部下のやつらも大したことなかったのに。何を思ってあんたたちみたいなやつらにアタシを任せたんだ？","ENG":"This is a let-down. Even your subordinates were too weak. What makes them think you can stand against me?","TWN":"真是掃興。手下的那些傢伙也不怎麼樣。到底是憑什麼把我交給你們這種傢伙對付的？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아니면 관리국이 우릴 잡으려고 강한 놈을 아껴둔 게 아니라, 너 같은 잔챙이들을 이용해서라도 시간을 벌어야 할 만큼 절박했단 건가?","JPN":"それか管理局がアタシたちを捕まえるために強いやつらをキープしておいたんじゃなくて、あんたみたいな雑魚を利用してでも時間を稼がなきゃいけないほど追い込まれていたとか？","ENG":"Or is it that the Administration wasn't hiding their strong ones to face us, but was trying to buy time by using chumps like you?","TWN":"難道為了拖住我們，連你們這樣的小嘍囉也要扔出來爭取時間，管理局已經到了如此絕望的地步了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"관리국은 지지 않아.","JPN":"管理局は負けない。","ENG":"The Administration will not lose.","TWN":"管理局……不會輸。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"모두가 함께 맹세했다. 마왕을 이기고… 세상을 구해낼 거라고.","JPN":"皆で一緒に誓ったんだ。魔王に勝ち……世界を救うと。","ENG":"We all made an oath. That we'll defeat the Demon Lord... and save the world.","TWN":"大家一起發誓了。要打敗魔王……拯救這個世界。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하핫! 그래, 자기가 따르는 무리를 믿는 게 나쁜 건 아니지.","JPN":"ははっ！　そうさ、自分が従っている群れを信じるのは悪いことじゃない。","ENG":"Haha! Yeah, it's not a bad thing to trust your people.","TWN":"哈哈！對啊，相信自己人總沒有錯。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};